            ContentJson = """{"title":"Purchase Orders Field Reference","groups":[{"heading":"PO Header Fields (Create Dialog)","items":[{"label":"Vendor (required)","value":"Dropdown selecting the vendor for this PO. Populated from the Vendors module. Must select a vendor before saving."},{"label":"Job (optional)","value":"Links the PO to a specific job. Useful for tracking material costs against a production run. Appears as a clickable entity link in the detail view."},{"label":"Notes (optional)","value":"Textarea for free-form notes about the order — special instructions, shipping preferences, or internal comments."}]},{"heading":"Line Item Fields (Create Dialog)","items":[{"label":"Part (required)","value":"Autocomplete field searching the Parts Catalog. Shows part number and description. Assembly-type parts are excluded — only purchasable parts appear."},{"label":"Ordered Quantity (required)","value":"Number input, minimum 1. How many units of this part to order. Defaults to 1 when adding a new line."},{"label":"Unit Price (required)","value":"Number input, minimum 0. Cost per unit. Auto-fills from the part's default price when a part is selected (indicated by a tooltip). Can be manually overridden."},{"label":"Line Total (computed)","value":"Displayed per line: Ordered Quantity multiplied by Unit Price. Not directly editable."},{"label":"Add Line button","value":"Adds the current part/quantity/price as a new line item. The line form resets after adding. At least one line item is required to save the PO."},{"label":"Remove Line (trash icon)","value":"Removes a line item from the PO before saving. Icon button on each line row."},{"label":"PO Total (computed)","value":"Sum of all line totals. Displayed at the bottom of the line items section in the create dialog."}]},{"heading":"PO Detail Fields (Read-Only)","items":[{"label":"PO Number","value":"Auto-generated unique identifier (e.g., PO-00042). Displayed prominently in the detail header."},{"label":"Status","value":"Color-coded chip showing current lifecycle stage. See PO Statuses section below."},{"label":"Vendor","value":"Clickable entity link to the vendor record. Opens vendor detail dialog."},{"label":"Job","value":"Clickable entity link to the linked job (if any). Opens job detail dialog."},{"label":"Expected Delivery Date","value":"Date when materials are expected to arrive. Shown in MM/dd/yyyy format."},{"label":"Submitted Date","value":"When the PO was sent to the vendor. Null until submitted."},{"label":"Acknowledged Date","value":"When the vendor confirmed the order. Null until acknowledged."},{"label":"Received Date","value":"When all items were fully received. Null until fully received."},{"label":"Created / Updated","value":"Timestamps showing when the PO was created and last modified."}]},{"heading":"Line Item Detail Fields","items":[{"label":"Part Number","value":"The part's identifier from the Parts Catalog. Clickable entity link to open part detail."},{"label":"Description","value":"Part description pulled from the catalog."},{"label":"Ordered Quantity","value":"Number of units ordered on this line."},{"label":"Received Quantity","value":"Number of units received so far. Updated via the Receive Items workflow."},{"label":"Remaining Quantity","value":"Ordered minus Received. Computed automatically. When zero, the line is fully received."},{"label":"Unit Price","value":"Cost per unit for this line."},{"label":"Line Total","value":"Ordered Quantity times Unit Price."},{"label":"Notes","value":"Optional per-line notes."}]},{"heading":"PO Statuses","items":[{"label":"Draft (gray chip)","value":"PO is being prepared. Can add/remove lines, edit, delete, or cancel. Not yet sent to vendor."},{"label":"Submitted (blue chip)","value":"PO has been sent to vendor. Waiting for acknowledgment. Can still cancel."},{"label":"Acknowledged (teal chip)","value":"Vendor confirmed the order. Can now receive items. Can still cancel."},{"label":"Partially Received (orange chip)","value":"Some items received but not all. Receive Items button remains available. Cannot cancel."},{"label":"Received (green chip)","value":"All line items fully received. Can be closed. No further receiving needed."},{"label":"Closed (gray chip)","value":"PO formally closed after receiving is complete. No further actions possible."},{"label":"Cancelled (red chip)","value":"PO was cancelled. Only Draft, Submitted, and Acknowledged POs can be cancelled. Requires confirmation dialog."}]},{"heading":"Receiving Fields (Receive Items Dialog)","items":[{"label":"Receivable Lines","value":"Shows only lines with remaining quantity greater than zero. Fully received lines are excluded."},{"label":"Quantity to Receive (per line)","value":"Number input per line, minimum 0, maximum is the remaining quantity. Enter how many units arrived for each line."},{"label":"Receive All button","value":"Fills in the remaining quantity for every receivable line. Convenience action for when the entire shipment arrives complete."},{"label":"Save","value":"Records the receiving event. Updates received quantities on each line. May change PO status to Partially Received or Received."}]},{"heading":"Blanket PO Fields","items":[{"label":"Is Blanket","value":"Toggle indicating this is a blanket (long-term) PO rather than a one-time order."},{"label":"Blanket Total Quantity","value":"Total quantity committed under the blanket agreement."},{"label":"Agreed Unit Price","value":"Negotiated price per unit for the blanket agreement."},{"label":"Blanket Expiration Date","value":"When the blanket agreement expires."},{"label":"Released Quantity","value":"Sum of quantities from all releases created against this blanket."},{"label":"Remaining Quantity","value":"Blanket Total minus Released. Computed automatically."}]},{"heading":"Blanket Release Fields","items":[{"label":"Line Item (required)","value":"Dropdown selecting which PO line item this release draws from."},{"label":"Quantity (required)","value":"Number of units for this release. Minimum 0.01."},{"label":"Requested Delivery Date (required)","value":"When you need this release delivered."},{"label":"Notes (optional)","value":"Free-form notes for this release."},{"label":"Release Status","value":"Open (blue), Sent (teal), Partial Received (orange), Received (green), Cancelled (red)."}]},{"heading":"Table Columns (List Page)","items":[{"label":"PO Number","value":"Sortable. Auto-generated PO identifier. Width: 120px."},{"label":"Vendor","value":"Sortable. Vendor company name."},{"label":"Job","value":"Sortable. Linked job number, if any. Width: 100px."},{"label":"Status","value":"Sortable, filterable (enum). Color-coded chip. Width: 140px."},{"label":"Lines","value":"Sortable, center-aligned. Number of line items on the PO. Width: 70px."},{"label":"Ordered","value":"Sortable, center-aligned. Total ordered quantity across all lines. Width: 90px."},{"label":"Received","value":"Sortable, center-aligned. Total received quantity across all lines. Width: 90px."},{"label":"Expected","value":"Sortable, date type. Expected delivery date. Width: 110px."},{"label":"Created","value":"Sortable, date type. When the PO was created. Width: 110px."}]},{"heading":"Buttons and Actions","items":[{"label":"New Purchase Order (primary button)","value":"Opens the PO creation dialog. data-testid: new-po-btn"},{"label":"Save (create dialog)","value":"Creates the PO with all line items. Disabled when form is invalid, no lines added, or save is in progress."},{"label":"Cancel (create dialog)","value":"Closes the dialog without saving."},{"label":"Submit PO","value":"Sends the PO to the vendor. Changes status from Draft to Submitted. Available only when status is Draft."},{"label":"Acknowledge PO","value":"Marks vendor acknowledgment. Changes status from Submitted to Acknowledged. Available only when status is Submitted."},{"label":"Receive Items","value":"Opens the receiving dialog. Available when status is Acknowledged or Partially Received."},{"label":"Close PO","value":"Formally closes a fully received PO. Available only when status is Received."},{"label":"Cancel PO","value":"Cancels the PO with confirmation dialog. Available when status is Draft, Submitted, or Acknowledged."},{"label":"Delete PO","value":"Permanently removes a draft PO with confirmation dialog. Available only when status is Draft. Severity: danger."},{"label":"Row click (list table)","value":"Opens the PO detail dialog showing header info, line items with quantities, receiving history, and available actions."},{"label":"Create Release (blanket POs)","value":"Opens dialog to create a new release against the blanket PO. Specifies line, quantity, and delivery date."}]},{"heading":"Validation Rules","items":[{"label":"Vendor","value":"Required. Must select a vendor from the dropdown."},{"label":"Line Items","value":"At least one line item is required. Validation popover shows 'At least one line item is required' when no lines exist."},{"label":"Part (line)","value":"Required. Must select a part from the autocomplete."},{"label":"Ordered Quantity (line)","value":"Required. Must be at least 1."},{"label":"Unit Price (line)","value":"Required. Must be 0 or greater."},{"label":"Receive Quantity","value":"Minimum 0, maximum is the remaining quantity for that line. At least one line must have quantity greater than 0 to save."},{"label":"Submit button popover","value":"When form is invalid, hovering over Save shows a validation popover listing which fields need attention."}]}]}"""
