            ContentJson = """{"appRoute":"/purchase-orders/suggestions","startButtonLabel":"Tour Auto-PO Suggestions","steps":[{"element":".tab-bar","popover":{"title":"Purchase Orders Tabs","description":"The Purchase Orders page has up to three tabs: Orders (your POs), Suggestions (Auto-PO proposals — you're here), and Settings (admin-only Auto-PO configuration). A badge on the Suggestions tab shows how many proposals are still pending.","side":"bottom"}},{"element":"[data-testid='auto-po-status-filter']","popover":{"title":"Status Filter","description":"Filter the suggestions by status: Pending (awaiting your decision), Converted (already turned into a PO), or Dismissed (rejected). The tab opens on Pending so you see what needs action first.","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Suggestions Table","description":"Each row is one proposed purchase: the part, the preferred vendor, the suggested quantity, the date it's needed by, the source sales orders that drove the demand, and the status. Part and vendor are clickable links to their records. Select one or more rows with the checkboxes to act on them in bulk.","side":"top"}},{"element":"[data-testid='auto-po-run-btn']","popover":{"title":"Run Analysis Now","description":"Auto-PO recalculates demand every night, but admins can force a fresh analysis here instead of waiting. After it runs, refresh to see newly raised suggestions. (This button is admin-only.)","side":"bottom"}},{"element":"app-data-table","popover":{"title":"Convert or Dismiss","description":"When you select one or more pending suggestions, Convert to PO and Dismiss buttons appear in the toolbar. Convert turns each selected suggestion into a purchase order (one or many at once); Dismiss removes proposals you don't intend to order. Converted suggestions move to the Converted status and a new PO appears on the Orders tab.","side":"top"}}]}"""
