        // ── Closing a PO Short (QuickRef) ────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Closing a PO Short",
            Slug = "purchase-orders-short-close",
            Summary = "When and how to short-close a partially-received purchase order: the difference from a normal close, the required reason, who can do it, and how the short-closed quantities are recorded for audit.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 8,
            AppRoutes = """["/purchase-orders"]""",
            Tags = """["purchase-orders","procurement","short-close","receiving","reference"]""",
            ContentJson = """{"title":"Closing a PO Short","groups":[{"heading":"What Short-Close Means","items":[{"label":"Definition","value":"Short-closing finalizes a partially-received PO when the remaining (un-received) quantity will never arrive — and you accept that. It closes the order with a documented reason instead of waiting indefinitely for the balance."},{"label":"Normal Close vs. Short-Close","value":"The regular Close action only works on a fully-received PO — closing a PO that still has remaining quantity is rejected. Short-Close is the path for closing a PO that is only partially received."},{"label":"Typical reasons","value":"Vendor backorder was cancelled, the item was discontinued, the remainder is no longer needed, or the small outstanding balance isn't worth chasing."}]},{"heading":"When the Button Appears","items":[{"label":"Status","value":"The Short Close button shows on the PO detail panel for any PO that is NOT Draft, Closed, or Cancelled — in practice, Submitted, Acknowledged, or Partially Received orders that still have an outstanding balance."},{"label":"Outstanding balance required","value":"At least one line must still have ordered quantity greater than received plus any previously short-closed quantity. If everything is received, you use the normal Close action instead."},{"label":"Who can do it","value":"Restricted to Admin, Manager, Office Manager, and Procurement roles. Other users won't see the Short Close button."}]},{"heading":"How to Short-Close","items":[{"label":"1. Open the PO","value":"Click the PO row on the Orders tab to open its detail panel."},{"label":"2. Click Short Close","value":"Find the Short Close action in the action row (alongside Cancel and Close). Its icon is a 'cancel scheduled send' glyph."},{"label":"3. Enter a reason","value":"A dialog opens requiring a reason. The reason is mandatory — the confirm button stays disabled until you provide one, and the server rejects a blank reason."},{"label":"4. Confirm","value":"Click Short Close in the dialog. The PO moves to Closed and the outstanding quantities are recorded as short-closed."}]},{"heading":"What Gets Recorded","items":[{"label":"Cancelled / Short-Closed Quantity","value":"Each line's un-received remainder is captured as its short-closed quantity. After a short-close, the line-items table shows an extra Short-Closed Qty column with these amounts."},{"label":"Reason & date (audit banner)","value":"The detail panel shows a 'Short Closed' banner with the reason you entered and the date, so Accounts Payable and procurement can see at a glance why the PO was closed with an unfilled balance."},{"label":"Final status","value":"The PO ends in Closed status. No further receiving, cancelling, or other actions are possible — short-close is terminal, the same as a normal close."}]},{"heading":"Short-Close vs. Cancel","items":[{"label":"Cancel","value":"Only available for Draft, Submitted, and Acknowledged POs — i.e., before anything has been received. It voids the whole order."},{"label":"Short-Close","value":"Used after partial receipt. It keeps the received portion (and its receiving records) intact and only closes out the unfilled remainder."},{"label":"Rule of thumb","value":"Nothing received yet and the whole order is dead → Cancel. Some received, the rest won't come → Short-Close."}]}]}"""
