            Summary = "Edge-case and power-user reference for purchase orders: the off-tier price prompt, manual per-line price overrides with reason audit, AI price-variance review, the PO barcode/QR label, the PO calendar feed, and draft auto-save.",
            ContentType = TrainingContentType.Reference,
